    Object.assign(summary.style, { display: "flex", alignItems: "center", gap: "8px" });
    const badge = document.createElement("span");
    Object.assign(badge.style, { fontSize: "9px", fontWeight: "700", padding: "1px 6px", borderRadius: "3px", background: "#1e1b4b", color: "#a5b4fc", letterSpacing: "0.05em", flexShrink: "0" });
    badge.textContent = "STATE";
