    changedBadge.setAttribute("data-testid", '"state-changed-count-" + entry.id');
    Object.assign(changedBadge.style, { fontSize: "9px", fontWeight: "700", padding: "1px 4px", borderRadius: "3px", background: "#451a03", color: "#fbbf24" });
    changedTpl.content.appendChild(changedBadge);
