  function handleGaleErrorDetail(event) {
    if (!event.detail) {
      return;
    }
    const { status, url, method: method2, payload, responseBody } = event.detail;
    if (status === 422) {
      return;
    }
    const statusMessages = {
      400: "Bad Request",
      401: "Unauthorized",
      403: "Forbidden",
      404: "Not Found",
      405: "Method Not Allowed",
      419: "CSRF token expired. Reload the page.",
      429: "Too Many Requests",
      500: "Internal Server Error",
      502: "Bad Gateway",
      503: "Service Unavailable",
      504: "Gateway Timeout"
    };
    const message = status === 419 ? "CSRF token expired. Reload the page." : statusMessages[status] || `HTTP ${status} Error`;
    enqueueError({
      errorSource: "server",
      status,
      message,
      requestContext: {
        url: url || "",
        method: method2 || "POST",
        payload: payload || null
      },
      responseBody: responseBody || null
    });
  }
  function showGaleErrorOverlay(errorData) {
    if (!isEnabled2()) {
      return;
    }
    enqueueError({
      errorSource: "client",
      message: errorData.message || "JavaScript error",
      stack: errorData.stack || null,
      operation: errorData.operation || null,
      componentState: errorData.componentState || null,
      requestContext: errorData.requestContext || null
    });
  }
